// 교육용 빅뱅 시뮬레이션 - 칠판 강의식 형식
// 시간이 지나면서 각 단계가 칠판에 그려집니다

export function createClassroomBlackboard() {
  const canvas = document.createElement('canvas');
  canvas.width = 1400;
  canvas.height = 900;
  const ctx = canvas.getContext('2d');

  // 칠판 배경 (어두운 초록색)
  const gradient = ctx.createLinearGradient(0, 0, 0, canvas.height);
  gradient.addColorStop(0, '#1a3a2a');
  gradient.addColorStop(1, '#0f2620');
  ctx.fillStyle = gradient;
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  // 칠판 테두리
  ctx.strokeStyle = '#8B7355';
  ctx.lineWidth = 15;
  ctx.strokeRect(10, 10, canvas.width - 20, canvas.height - 20);

  // 제목
  ctx.fillStyle = '#FFFFFF';
  ctx.font = 'bold 48px Arial';
  ctx.textAlign = 'center';
  ctx.fillText('The Big Bang: 우주의 진화', canvas.width / 2, 60);

  // 시간축 (가로줄)
  ctx.strokeStyle = '#ffff99';
  ctx.lineWidth = 2;
  ctx.setLineDash([10, 5]);
  ctx.beginPath();
  ctx.moveTo(100, 750);
  ctx.lineTo(canvas.width - 100, 750);
  ctx.stroke();
  ctx.setLineDash([]);

  // 시간축 레이블
  ctx.fillStyle = '#ffff99';
  ctx.font = 'bold 16px Arial';
  ctx.textAlign = 'left';
  ctx.fillText('10⁻¹² s', 100, 800);
  ctx.fillText('10⁻⁶ s', 400, 800);
  ctx.fillText('1-3 min', 700, 800);
  ctx.fillText('380,000 years', 1000, 800);

  return canvas;
}

export function updateClassroomBlackboard(canvas, time) {
  const ctx = canvas.getContext('2d');

  // 칠판 배경
  const gradient = ctx.createLinearGradient(0, 0, 0, canvas.height);
  gradient.addColorStop(0, '#1a3a2a');
  gradient.addColorStop(1, '#0f2620');
  ctx.fillStyle = gradient;
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  // 칠판 테두리
  ctx.strokeStyle = '#8B7355';
  ctx.lineWidth = 15;
  ctx.strokeRect(10, 10, canvas.width - 20, canvas.height - 20);

  // 제목
  ctx.fillStyle = '#FFFFFF';
  ctx.font = 'bold 48px Arial';
  ctx.textAlign = 'center';
  ctx.fillText('The Big Bang: 우주의 진화', canvas.width / 2, 60);

  // 시간축
  ctx.strokeStyle = '#ffff99';
  ctx.lineWidth = 2;
  ctx.setLineDash([10, 5]);
  ctx.beginPath();
  ctx.moveTo(100, 750);
  ctx.lineTo(canvas.width - 100, 750);
  ctx.stroke();
  ctx.setLineDash([]);

  // 시간축 레이블
  ctx.fillStyle = '#ffff99';
  ctx.font = 'bold 14px Arial';
  ctx.textAlign = 'left';
  ctx.fillText('10⁻¹² s', 100, 800);
  ctx.fillText('10⁻⁶ s', 380, 800);
  ctx.fillText('1-3 min', 680, 800);
  ctx.fillText('380k years', 980, 800);

  // 각 단계별 애니메이션
  const stages = [
    { x: 150, y: 200, duration: 2, delay: 0 },      // Stage 0: QGP
    { x: 450, y: 200, duration: 2.5, delay: 2 },    // Stage 1: Quarks
    { x: 750, y: 200, duration: 2.5, delay: 4.5 },  // Stage 2: Nucleosynthesis
    { x: 1050, y: 200, duration: 3, delay: 7 }      // Stage 3: Atoms
  ];

  stages.forEach((stage, idx) => {
    const elapsed = time - stage.delay;

    // 단계별 진행도 (0~1)
    const progress = Math.max(0, Math.min(1, elapsed / stage.duration));

    if (progress > 0) {
      drawStageOnBlackboard(ctx, idx, stage.x, stage.y, progress);

      // 단계명과 시간
      drawStageLabel(ctx, idx, stage.x, stage.y, progress);
    }
  });

  // 현재 시간 표시
  ctx.fillStyle = '#00ff00';
  ctx.font = 'bold 14px Arial';
  ctx.textAlign = 'right';
  ctx.fillText(`t = ${time.toFixed(1)}s (simulation)`, canvas.width - 50, 850);
}

function drawStageOnBlackboard(ctx, stageIdx, x, y, progress) {
  // 분필 색상 (각 단계별 다른 색상)
  const colors = [
    '#FF6B6B',  // 빨강 - QGP
    '#4ECDC4',  // 청록 - Quarks
    '#95E77D',  // 초록 - Nucleosynthesis
    '#B0A0FF'   // 보라 - Atoms
  ];

  ctx.strokeStyle = colors[stageIdx];
  ctx.fillStyle = colors[stageIdx];
  ctx.globalAlpha = 0.7 + progress * 0.3;

  switch (stageIdx) {
    case 0:
      // 쿼크-글루온 플라즈마: 중앙 뭉치 + 회전 궤도
      drawDrawnCore(ctx, x, y, 15, progress);
      drawDrawnOrbit(ctx, x, y, 40, progress * 0.8);
      drawDrawnOrbit(ctx, x, y, 65, progress * 0.6);
      drawDrawnOrbit(ctx, x, y, 90, progress * 0.4);
      break;

    case 1:
      // 양성자/중성자: 커진 중앙 + 2개 궤도
      drawDrawnCore(ctx, x, y, 20, progress);
      drawDrawnOrbit(ctx, x, y, 45, progress * 0.9);
      drawDrawnOrbit(ctx, x, y, 70, progress * 0.7);
      break;

    case 2:
      // 핵융합: 더 큰 중앙 + 1개 궤도
      drawDrawnCore(ctx, x, y, 25, progress);
      drawDrawnOrbit(ctx, x, y, 50, progress);
      break;

    case 3:
      // 원자: 작은 핵 + 3개 전자 껍질
      drawDrawnAtom(ctx, x, y, progress);
      break;
  }

  ctx.globalAlpha = 1.0;
}

// 분필로 그린 느낌의 중앙 뭉치
function drawDrawnCore(ctx, x, y, radius, progress) {
  const drawRadius = radius * progress;

  // 분필 느낌: 여러 겹으로 그려서 자연스러움
  for (let i = 0; i < 5; i++) {
    ctx.globalAlpha = 0.3 - i * 0.05;
    ctx.beginPath();
    ctx.arc(x, y, drawRadius + i * 2, 0, Math.PI * 2);
    ctx.fill();
  }

  ctx.globalAlpha = 0.7;
  ctx.beginPath();
  ctx.arc(x, y, drawRadius, 0, Math.PI * 2);
  ctx.fill();
}

// 분필로 그린 느낌의 궤도
function drawDrawnOrbit(ctx, x, y, radius, progress) {
  const drawRadius = radius * progress;

  ctx.lineWidth = 2;

  // 분필 느낌: 점선으로 궤도 표현
  ctx.setLineDash([8, 4]);
  for (let i = 0; i < 3; i++) {
    ctx.globalAlpha = 0.5 - i * 0.1;
    ctx.beginPath();
    ctx.arc(x, y, drawRadius + i, 0, Math.PI * 2);
    ctx.stroke();
  }
  ctx.setLineDash([]);

  // 궤도상의 입자들
  ctx.globalAlpha = 0.8;
  const numParticles = Math.max(3, Math.floor(drawRadius * 1.5));
  for (let i = 0; i < numParticles; i++) {
    const angle = (i / numParticles) * Math.PI * 2;
    const px = x + Math.cos(angle) * drawRadius;
    const py = y + Math.sin(angle) * drawRadius;

    ctx.beginPath();
    ctx.arc(px, py, 2, 0, Math.PI * 2);
    ctx.fill();
  }
}

// 분필로 그린 원자 (보어 모델)
function drawDrawnAtom(ctx, x, y, progress) {
  ctx.lineWidth = 2;

  // 작은 핵
  ctx.globalAlpha = 0.9;
  ctx.beginPath();
  ctx.arc(x, y, 5, 0, Math.PI * 2);
  ctx.fill();

  // 3개 전자 껍질
  const shellRadii = [30, 55, 80];
  shellRadii.forEach((shellRadius, idx) => {
    const drawRadius = shellRadius * progress;

    if (drawRadius > 0) {
      // 분필 느낌: 떨리는 선으로
      ctx.globalAlpha = 0.6;
      ctx.setLineDash([6, 3]);
      ctx.beginPath();
      ctx.arc(x, y, drawRadius, 0, Math.PI * 2);
      ctx.stroke();
      ctx.setLineDash([]);

      // 전자 입자들
      ctx.globalAlpha = 0.8;
      const numElectrons = 3 + idx * 2;
      for (let i = 0; i < numElectrons; i++) {
        const angle = (i / numElectrons) * Math.PI * 2 + Date.now() * 0.001 * (idx + 1) * 0.5;
        const px = x + Math.cos(angle) * drawRadius;
        const py = y + Math.sin(angle) * drawRadius;

        ctx.beginPath();
        ctx.arc(px, py, 2.5, 0, Math.PI * 2);
        ctx.fill();
      }
    }
  });
}

// 단계별 레이블
function drawStageLabel(ctx, stageIdx, x, y, progress) {
  const labels = [
    { title: 'Stage 2: QGP', desc: '쿼크-글루온\n플라즈마' },
    { title: 'Stage 3: Hadrons', desc: '양성자/중성자\n형성' },
    { title: 'Stage 4: Nuclei', desc: '원자핵\n형성' },
    { title: 'Stage 5: Atoms', desc: '원자\n형성' }
  ];

  const label = labels[stageIdx];

  // 제목
  ctx.fillStyle = '#FFFFFF';
  ctx.font = 'bold 14px Arial';
  ctx.textAlign = 'center';
  ctx.fillText(label.title, x, y + 130);

  // 설명 (진행도에 따라 타이핑 효과)
  ctx.fillStyle = '#FFFF99';
  ctx.font = '12px Arial';

  const descLines = label.desc.split('\n');
  const typingProgress = Math.floor(progress * 30); // 최대 30글자

  let charCount = 0;
  descLines.forEach((line, lineIdx) => {
    let displayText = '';
    for (let i = 0; i < line.length; i++) {
      if (charCount < typingProgress) {
        displayText += line[i];
      }
      charCount++;
    }
    ctx.fillText(displayText, x, y + 150 + lineIdx * 18);
  });
}

// 단계 정보
export const educationalBigBangStages = [
  {
    id: 0,
    name: "쿼크-글루온 플라즈마",
    timeRange: "10⁻¹² 초",
    description: "우주 극초기 - 극도로 뜨거운 상태"
  },
  {
    id: 1,
    name: "양성자/중성자 형성",
    timeRange: "10⁻⁶ 초",
    description: "쿼크들이 결합하기 시작"
  },
  {
    id: 2,
    name: "핵융합 → 원자핵",
    timeRange: "1-3 분",
    description: "헬륨-4, 리튬 등 형성"
  },
  {
    id: 3,
    name: "원자 형성",
    timeRange: "38만 년",
    description: "전자가 원자핵 주변을 돌기 시작"
  }
];
